// Assemble the single-transaction SQL from the bundle. §234: all-or-nothing.
// NOTE: values are embedded for readability; migrate to parameterized query fields
// before production (documented risk).
const b = $('When Executed by WF-001').first().json;
const q = (s)=> String(s==null?'':s).replace(/'/g, "''");   // minimal escaping (TEXT columns)

// UUID emitter. q() coerces null/undefined -> '' and every call site wraps the
// result in quotes, which yields  id=''  for an absent value. Postgres accepts ''
// for TEXT but REJECTS it for UUID:  invalid input syntax for type uuid: ""
//
// Every repository `id` is  UUID PRIMARY KEY DEFAULT uuid_generate_v4()  — the
// database mints it when the column is OMITTED or given the DEFAULT keyword.
// NULL is NOT usable here: a PRIMARY KEY is implicitly NOT NULL, so an explicit
// NULL would trade one error for another ("null value ... violates not-null").
// Hence: absent -> the bare token DEFAULT.
//
// Returns a complete SQL token (quoted literal, or the bare word DEFAULT), so
// call sites must NOT wrap it in quotes.
const uid = (v) => (v == null || v === '')
  ? 'DEFAULT'
  : `'${String(v).replace(/'/g, "''")}'`;

// Foreign keys are NOT NULL in every table and must never be absent. Fail loudly
// rather than emitting DEFAULT (which would silently mint an unrelated UUID) or ''
// (which is the bug this replaces).
const fk = (v, col) => {
  if (v == null || v === '') {
    throw new Error(`SW-014: required FK ${col} is ${JSON.stringify(v)} — refusing to `
      + `emit an empty UUID. Upstream did not supply it.`);
  }
  return `'${String(v).replace(/'/g, "''")}'`;
};
const stmts = [];
stmts.push('BEGIN;');
stmts.push(`UPDATE repository.documents SET status='PROCESSED' WHERE id=${fk(b.documentId,'documentId')};`);
for (const m of (b.metadata||[])) stmts.push(`INSERT INTO repository.metadata (document_id,key,value) VALUES (${fk(b.documentId,'documentId')},'${q(m.key)}','${q(m.value)}');`);
for (const k of (b.accepted||b.acceptedUnits||[])) stmts.push(`INSERT INTO repository.knowledge_units (id,document_id,content,category,authority,status) VALUES (${uid(k.id)},${fk(b.documentId,'documentId')},'${q(k.statement)}','${q(k.category)}','${q(k.authoritySource)}','Draft');`);
for (const e of (b.evidence||[])) stmts.push(`INSERT INTO repository.evidence (id,knowledge_unit_id,excerpt) VALUES (${uid(e.id)},${fk(e.knowledgeUnitId,'evidence.knowledgeUnitId')},'${q(e.excerpt)}');`);
for (const c of (b.citations||[])) stmts.push(`INSERT INTO repository.citations (id,evidence_id,document_id,page,section) VALUES (${uid(c.id)},${fk(c.evidenceId,'citations.evidenceId')},${fk(b.documentId,'documentId')},${c.page==null?'NULL':Number(c.page)},'${q(c.section)}');`);
for (const ch of (b.chunks||[])) stmts.push(`INSERT INTO repository.retrieval_chunks (id,knowledge_unit_id,chunk_order,content) VALUES (${uid(ch.id)},${fk(ch.knowledgeUnitId,'chunks.knowledgeUnitId')},${Number(ch.ordinal||0)},'${q(ch.text)}');`);
for (const em of (b.embeddings||[])) stmts.push(`INSERT INTO repository.embeddings (id,chunk_id,embedding) VALUES (${uid(em.id)},${fk(em.chunkId,'embeddings.chunkId')},'[${(em.vector||[]).join(',')}]');`);
stmts.push('COMMIT;');
return [{ json: { _txn: stmts.join('\n'),
  _counts: { knowledgeUnits:(b.accepted||b.acceptedUnits||[]).length, evidence:(b.evidence||[]).length,
             citations:(b.citations||[]).length, chunks:(b.chunks||[]).length, embeddings:(b.embeddings||[]).length } } }];

// Enrichment: preserve incoming item, add { written, ...counts }.
const incoming = $('When Executed by WF-001').first().json;
return [{ json: { ...incoming, written: true, ...$('Build Transaction').first().json._counts } }];
